((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 74), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka menjawab: "(Bukan karena itu) sebenarnya kami mendapati nenek moyang kami berbuat demikian".', NOW(), NOW()),
