((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 76), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'kamu dan nenek moyang kamu yang dahulu?,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 77), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'karena sesungguhnya apa yang kamu sembah itu adalah musuhku, kecuali Tuhan Semesta Alam,', NOW(), NOW()),
