((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 79), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Tuhanku, Yang Dia memberi makan dan minum kepadaku,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 80), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan apabila aku sakit, Dialah Yang menyembuhkan aku,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 81), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan Yang akan mematikan aku, kemudian akan menghidupkan aku (kembali),', NOW(), NOW()),
