((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 86), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan ampunilah bapakku, karena sesungguhnya ia adalah termasuk golongan orang-orang yang sesat,', NOW(), NOW()),
