((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 96), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Mereka berkata sedang mereka bertengkar di dalam neraka:', NOW(), NOW()),
