((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 98), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'karena kita mempersamakan kamu dengan Tuhan semesta alam".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 99), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Dan tiadalah yang menyesatkan kami kecuali orang-orang yang berdosa.', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 100), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Maka kami tidak mempunyai pemberi syafa''at seorangpun,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 101), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'dan tidak pula mempunyai teman yang akrab,', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 102), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'maka sekiranya kita dapat kembali sekali lagi (ke dunia) niscaya kami menjadi orang-orang yang beriman".', NOW(), NOW()),
((SELECT a.id FROM mst_ayah a JOIN mst_surah s ON s.id = a.surah_id WHERE s.surah_number = 26 AND a.ayah_number = 103), (SELECT id FROM mst_language WHERE code = 'id'), 'Kementerian Agama RI', 'Sesungguhnya pada yang demikian itu benar-benar terdapat tanda-tanda (kekuasaan Allah), tetapi kebanyakan mereka tidak beriman.', NOW(), NOW()),
